INSERT INTO `questions` (`id`, `quiz_id`, `question_text`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_answer`, `explanation`, `points`, `difficulty`, `created_at`) VALUES (1,1,'What is the place value of 7 in the number 3,742?','Units','Tens','Hundreds','Thousands','C','In 3,742 the digit 7 is in the hundreds position.',10,'easy','2026-05-10 17:03:14'),(2,1,'Which number is the largest?','9,099','9,909','9,990','9,900','C','9,990 has 9 in the thousands, 9 in the hundreds, 9 in the tens.',10,'easy','2026-05-10 17:03:14'),(3,1,'Round 3,456 to the nearest hundred.','3,400','3,500','3,456','3,000','B','3,456 rounds to 3,500 because the tens digit (5) is 5 or more.',10,'easy','2026-05-10 17:03:14'),(4,1,'What is 1,000 × 45?','450','4,500','45,000','450,000','C','Multiplying by 1,000 adds three zeros.',10,'easy','2026-05-10 17:03:14'),(5,1,'Express 2,500,000 in words.','Two thousand five hundred','Two million five hundred thousand','Twenty-five million','Two hundred fifty thousand','B','2,500,000 = Two million, five hundred thousand.',10,'easy','2026-05-10 17:03:14'),(6,2,'What is 1/2 + 1/4?','2/6','3/4','2/4','1/6','B','1/2 = 2/4. So 2/4 + 1/4 = 3/4',10,'easy','2026-05-10 17:03:14'),(7,2,'Which fraction is equivalent to 2/3?','4/9','6/9','4/6','3/4','C','4/6 = 2/3 when simplified by dividing by 2.',10,'easy','2026-05-10 17:03:14'),(8,2,'Convert 0.75 to a fraction.','7/5','3/4','7/10','75/10','B','0.75 = 75/100 = 3/4',10,'easy','2026-05-10 17:03:14'),(9,2,'What is 3/4 of 20?','12','15','10','8','B','3/4 × 20 = 60/4 = 15',10,'easy','2026-05-10 17:03:14'),(10,2,'Arrange in ascending order: 1/2, 1/3, 2/3','1/3, 1/2, 2/3','1/2, 1/3, 2/3','2/3, 1/2, 1/3','1/3, 2/3, 1/2','A','Convert to same denominator: 2/6, 3/6, 4/6. Order: 1/3 < 1/2 < 2/3',10,'easy','2026-05-10 17:03:14'),(11,5,'How many sides does a hexagon have?','5','6','7','8','B','Hex = 6. A hexagon has 6 sides.',10,'easy','2026-05-10 17:03:14'),(12,5,'What is the sum of angles in a triangle?','90°','180°','270°','360°','B','The interior angles of any triangle always add up to 180°.',10,'easy','2026-05-10 17:03:14'),(13,5,'A square has side length 5cm. What is its area?','10 cm²','20 cm²','25 cm²','15 cm²','C','Area of square = side × side = 5 × 5 = 25 cm²',10,'easy','2026-05-10 17:03:14'),(14,5,'What shape has all sides equal and all angles 90°?','Rectangle','Rhombus','Square','Trapezoid','C','A square has equal sides AND right angles.',10,'easy','2026-05-10 17:03:14'),(15,5,'The circumference of a circle with radius 7cm is approximately?','22 cm','44 cm','14 cm','154 cm','B','C = 2πr = 2 × 22/7 × 7 = 44 cm',10,'easy','2026-05-10 17:03:14'),(16,6,'Identify the VERB: \"The students studied hard.\"','The','students','studied','hard','C','\"Studied\" is the action in the sentence - it is a verb.',10,'easy','2026-05-10 17:03:14'),(17,6,'What type of word is \"quickly\"?','Adjective','Noun','Verb','Adverb','D','\"Quickly\" describes HOW something is done - it is an adverb.',10,'easy','2026-05-10 17:03:14'),(18,6,'Choose the ADJECTIVE in: \"The bright star shone.\"','The','bright','star','shone','B','\"Bright\" describes the noun \"star\" - it is an adjective.',10,'easy','2026-05-10 17:03:14'),(19,6,'Which sentence uses a PRONOUN?','Ama likes books.','She likes books.','Books are good.','Reading is fun.','B','\"She\" is a pronoun - it replaces a noun (Ama).',10,'easy','2026-05-10 17:03:14'),(20,6,'What is the NOUN in: \"Kofi runs fast.\"','runs','fast','Kofi','all of them','C','\"Kofi\" is a person - it is a proper noun.',10,'easy','2026-05-10 17:03:14'),(21,9,'Which is NOT a characteristic of living things?','Growth','Reproduction','Rusting','Response to stimuli','C','Rusting is a chemical reaction that happens to metals, not a life process.',10,'easy','2026-05-10 17:03:14'),(22,9,'What do plants use to make their own food?','Sunlight only','Water and minerals only','Sunlight, water and carbon dioxide','Oxygen and soil','C','Photosynthesis uses sunlight, water (H2O) and carbon dioxide (CO2).',10,'easy','2026-05-10 17:03:14'),(23,9,'Which organism is a producer?','Grasshopper','Grass','Frog','Eagle','B','Producers (plants like grass) make their own food through photosynthesis.',10,'easy','2026-05-10 17:03:14'),(24,9,'How do animals differ from plants?','Animals cannot reproduce','Animals cannot move','Animals cannot make their own food','Animals do not grow','C','Animals are consumers - they must eat other organisms for energy.',10,'easy','2026-05-10 17:03:14'),(25,9,'What is respiration?','Breathing in and out','The process of releasing energy from food','Making food with sunlight','Getting rid of waste','B','Cellular respiration releases energy from glucose for life processes.',10,'easy','2026-05-10 17:03:14'),(26,12,'What does a map scale of 1:50,000 mean?','1cm on map = 50cm in real life','1cm on map = 500m in real life','1cm on map = 50km in real life','1cm on map = 5km in real life','B','1:50,000 means 1cm represents 50,000cm = 500m in reality.',10,'easy','2026-05-10 17:03:14'),(27,12,'Which direction is opposite to North?','East','West','South','Northeast','C','North and South are opposite directions on a compass.',10,'easy','2026-05-10 17:03:14'),(28,12,'What do contour lines on a map show?','Rivers and lakes','Roads and paths','Height above sea level','Country borders','C','Contour lines connect points of equal elevation (height).',10,'easy','2026-05-10 17:03:14'),(29,12,'A map legend is used to?','Show the scale of the map','Explain the symbols used','Show the compass direction','Label the rivers','B','The legend (key) explains what each symbol on the map represents.',10,'easy','2026-05-10 17:03:14'),(30,12,'What colour usually represents water on maps?','Green','Brown','Blue','Red','C','Blue is the conventional colour for water bodies on maps.',10,'easy','2026-05-10 17:03:14'),(31,14,'What is the main purpose of Religious and Moral Education?','To teach only one religion','To help learners develop faith, values and good behaviour','To replace all other school subjects','To teach only history','B','RME helps learners understand religious ideas, moral values and responsible behaviour.',10,'easy','2026-05-10 17:03:14'),(32,14,'Which of these is a moral value?','Dishonesty','Respect','Laziness','Selfishness','B','Respect is a moral value because it guides people to treat others well.',10,'easy','2026-05-10 17:03:14'),(33,14,'Where can learners practise moral values?','Only in church or mosque','Only during examinations','At home, in school and in the community','Only when adults are watching','C','Moral values should guide behaviour everywhere.',10,'easy','2026-05-10 17:03:14'),(34,14,'Which behaviour shows responsibility?','Blaming others for your work','Doing assigned duties on time','Ignoring school rules','Refusing to help anyone','B','Doing assigned duties on time is a responsible action.',10,'easy','2026-05-10 17:03:14'),(35,14,'Why is tolerance important?','It helps people live peacefully despite differences','It makes everyone think the same way','It stops people from learning','It encourages disrespect','A','Tolerance means accepting and respecting differences, which supports peaceful living.',10,'easy','2026-05-10 17:03:14'),(36,15,'According to many religions, who created the world?','Human beings','Machines','God','Animals','C','Many religions teach that God is the creator of the world.',10,'easy','2026-05-10 17:03:14'),(37,15,'Which action shows care for creation?','Planting trees','Throwing rubbish into drains','Wasting water','Burning every plant','A','Planting trees helps protect and care for the environment.',10,'easy','2026-05-10 17:03:14'),(38,15,'Why should humans use natural resources wisely?','Resources can be wasted without effect','To protect them for present and future use','To destroy the environment quickly','To prevent farming','B','Wise use of resources helps communities today and protects resources for the future.',10,'easy','2026-05-10 17:03:14'),(39,15,'Which of these harms the environment?','Keeping surroundings clean','Recycling useful materials','Dumping waste in rivers','Saving water','C','Dumping waste in rivers pollutes water and harms living things.',10,'easy','2026-05-10 17:03:14'),(40,15,'Human responsibility toward creation includes','Destroying plants for fun','Protecting living things','Polluting the air','Wasting food and water','B','Protecting living things is part of caring for creation.',10,'easy','2026-05-10 17:03:14'),(41,16,'What is one role of a religious leader?','To guide and teach believers','To encourage fighting','To stop people from worshipping','To hide moral lessons','A','Religious leaders guide people in worship, belief and moral conduct.',10,'easy','2026-05-10 17:03:14'),(42,16,'Which sacred text is used by Christians?','The Bible','The Atlas','The dictionary','A timetable','A','The Bible is a sacred text used by Christians.',10,'easy','2026-05-10 17:03:14'),(43,16,'Which sacred text is used by Muslims?','The Qur\'an','A storybook','A newspaper','A map','A','The Qur\'an is the sacred text used by Muslims.',10,'easy','2026-05-10 17:03:14'),(44,16,'Why are sacred texts important?','They only decorate buildings','They provide guidance for faith and good conduct','They replace all teachers','They are used only for counting','B','Sacred texts guide believers in worship, faith and moral behaviour.',10,'medium','2026-05-10 17:03:14'),(45,16,'Traditional religious teachings are often passed on through','Proverbs, stories and customs','Traffic lights only','Computer passwords','Sports scores','A','Traditional teachings may be shared through stories, proverbs, customs and community practice.',10,'medium','2026-05-10 17:03:14'),(46,17,'Which action best shows honesty?','Returning money you found','Copying in a test','Lying to avoid punishment','Taking what is not yours','A','Returning money you found shows truthfulness and respect for others property.',10,'easy','2026-05-10 17:03:14'),(47,17,'Respect in the community means','Insulting elders','Listening politely to others','Ignoring rules','Mocking people who are different','B','Listening politely to others is one way to show respect.',10,'easy','2026-05-10 17:03:14'),(48,17,'Why is obedience to good rules important?','It causes confusion','It helps maintain order and safety','It prevents learning','It encourages cheating','B','Good rules help people live and work together safely.',10,'easy','2026-05-10 17:03:14'),(49,17,'Which value helps people support those in need?','Kindness','Pride','Greed','Disrespect','A','Kindness encourages people to care for and help others.',10,'easy','2026-05-10 17:03:14'),(50,17,'A responsible student should','Complete assignments and care for school property','Destroy school property','Always blame classmates','Avoid every duty','A','Completing assignments and caring for property are responsible behaviours.',10,'easy','2026-05-10 17:03:14'),(51,18,'What is conflict?','A disagreement between people or groups','A form of peaceful greeting','A school subject','A type of food','A','Conflict is a disagreement or misunderstanding between people or groups.',10,'easy','2026-05-10 17:03:14'),(52,18,'Which action helps resolve conflict peacefully?','Listening to both sides','Shouting louder','Spreading rumours','Refusing to talk','A','Listening helps people understand the problem and find a fair solution.',10,'easy','2026-05-10 17:03:14'),(53,18,'What does forgiveness help people do?','Continue anger forever','Restore peace after wrongdoing','Increase conflict','Avoid responsibility','B','Forgiveness can help restore peace when people accept responsibility and change.',10,'medium','2026-05-10 17:03:14'),(54,18,'Who can help two people settle a disagreement fairly?','A mediator','A cheater','A gossip','A bully','A','A mediator helps people discuss issues and reach a fair agreement.',10,'medium','2026-05-10 17:03:14'),(55,18,'Which choice best promotes peaceful living?','Using violence when angry','Apologising when you are wrong','Ignoring everyone','Keeping revenge in mind','B','Apologising when wrong helps repair relationships and promotes peace.',10,'easy','2026-05-10 17:03:14'),(56,19,'What does RME stand for?','Reading and Moral English','Religious and Moral Education','Regional Mathematics Exercise','Rights and Modern Economics','B','RME means Religious and Moral Education.',10,'easy','2026-05-10 17:03:14'),(57,19,'Which part of RME teaches learners to choose right actions?','Moral education','Physical training','Map reading','Typing practice','A','Moral education helps learners know and choose right actions.',10,'easy','2026-05-10 17:03:14'),(58,19,'Why do learners study different religions in RME?','To disrespect other beliefs','To build understanding, tolerance and respect','To stop all worship','To avoid learning values','B','Learning about different religions helps learners respect others and live peacefully.',10,'easy','2026-05-10 17:03:14'),(59,19,'Which example shows RME in everyday life?','Helping a classmate who is struggling','Refusing to greet others','Cheating during a quiz','Destroying school property','A','Helping others shows kindness and responsibility, which are values taught in RME.',10,'easy','2026-05-10 17:03:14'),(60,19,'How can RME help a school community?','By encouraging conflict and disrespect','By promoting discipline, peace and good relationships','By making rules unnecessary','By stopping students from helping others','B','RME promotes values that support discipline, peace and good relationships.',10,'easy','2026-05-10 17:03:14'),(61,20,'Which action best shows environmental stewardship?','Keeping a clean compound','Throwing plastic into gutters','Cutting trees without replacing them','Leaving taps running','A','Environmental stewardship means caring responsibly for the environment.',10,'easy','2026-05-10 17:03:14'),(62,20,'Why should learners avoid wasting water?','Water is useful for life and should be conserved','Water has no value','Wasting water is always helpful','Only adults need water','A','Water supports life, so people should use it wisely.',10,'easy','2026-05-10 17:03:14'),(63,20,'Which habit protects school surroundings?','Sweeping and disposing of litter properly','Writing on walls','Breaking plants','Dumping food waste anywhere','A','Keeping the school clean protects the surroundings and promotes health.',10,'easy','2026-05-10 17:03:14'),(64,20,'What can happen when rivers are polluted?','Water becomes safer to drink','Fish and people may be harmed','Plants grow without limits','Disease disappears','B','Polluted rivers can harm aquatic life and human health.',10,'medium','2026-05-10 17:03:14'),(65,20,'Which choice shows gratitude for creation?','Using resources carefully','Destroying useful plants','Burning rubbish anywhere','Ignoring sanitation rules','A','Using resources carefully shows appreciation and responsibility.',10,'easy','2026-05-10 17:03:14'),(66,21,'A religious leader helps followers mainly by','Teaching faith and good behaviour','Promoting hatred','Breaking community rules','Discouraging prayer','A','Religious leaders teach faith, worship and good conduct.',10,'easy','2026-05-10 17:03:14'),(67,21,'Which quality should a good religious leader show?','Honesty','Cruelty','Greed','Disrespect','A','Honesty helps leaders guide others with trust.',10,'easy','2026-05-10 17:03:14'),(68,21,'Sacred texts are respected because they','Guide believers in worship and conduct','Are used only for decoration','Stop people from learning','Have no moral lessons','A','Sacred texts contain teachings that guide belief and behaviour.',10,'easy','2026-05-10 17:03:14'),(69,21,'A lesson from sacred texts can help learners','Make good moral decisions','Avoid responsibility','Disrespect parents','Refuse peace','A','Sacred teachings can guide learners to make good choices.',10,'medium','2026-05-10 17:03:14'),(70,21,'Why should people respect different religious leaders?','It pr