/*!40000 ALTER TABLE `topics` DISABLE KEYS */;
INSERT INTO `topics` (`id`, `subject_id`, `school_id`, `created_by_teacher_id`, `title`, `description`, `difficulty`, `sequence_order`, `class_level`, `estimated_minutes`, `content`, `approval_status`, `is_active`, `reviewed_by_admin_id`, `reviewed_at`, `rejection_reason`, `created_at`) VALUES (1,1,NULL,NULL,'Whole Numbers and Place Value','Understanding millions, billions and place value','easy',1,'JHS1',30,'Learn about whole numbers up to millions. Place value helps us understand the value of each digit in a number.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(2,1,NULL,NULL,'Fractions and Decimals','Operations with fractions and decimal numbers','easy',2,'JHS1',35,'Fractions represent parts of a whole. Decimals are another way to write fractions with denominators of 10, 100, 1000.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(3,1,NULL,NULL,'Percentages','Understanding and calculating percentages','medium',3,'JHS1',30,'Percent means \"per hundred\". 50% = 50/100 = 0.5','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(4,1,NULL,NULL,'Basic Algebra','Introduction to variables and simple equations','medium',4,'JHS1',40,'Algebra uses letters to represent unknown numbers. x + 5 = 10 means x = 5','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(5,1,NULL,NULL,'Geometry - Shapes','Properties of 2D and 3D shapes','easy',5,'JHS1',35,'Learn about triangles, squares, circles and their properties.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(6,2,NULL,NULL,'Parts of Speech','Nouns, verbs, adjectives, adverbs and more','easy',1,'JHS1',30,'Every word in a sentence plays a role. Nouns name things, verbs show actions.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(7,2,NULL,NULL,'Reading Comprehension','Understanding and analyzing texts','easy',2,'JHS1',35,'Read carefully, identify main ideas, supporting details and author\'s purpose.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(8,2,NULL,NULL,'Essay Writing','Structure and techniques for writing essays','medium',3,'JHS1',40,'A good essay has introduction, body paragraphs and conclusion.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(9,2,NULL,NULL,'Tenses and Grammar','Past, present and future tenses','medium',4,'JHS1',30,'Tenses tell us WHEN an action happens.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(10,3,NULL,NULL,'Living and Non-living Things','Characteristics of living organisms','easy',1,'JHS1',30,'Living things grow, reproduce, respond to stimuli and need energy.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(11,3,NULL,NULL,'Plant Biology','Structure and functions of plants','easy',2,'JHS1',35,'Plants make their own food through photosynthesis.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(12,3,NULL,NULL,'Human Body Systems','Digestive, respiratory and circulatory systems','medium',3,'JHS1',40,'The human body has many systems working together to keep us alive.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(13,3,NULL,NULL,'Matter and Materials','States of matter and properties','easy',4,'JHS1',30,'Matter exists as solid, liquid or gas.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(14,4,NULL,NULL,'Map Reading Skills','Understanding maps, symbols and scale','easy',1,'JHS1',30,'Maps are scale drawings of Earth\'s surface.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(15,4,NULL,NULL,'Ghana\'s History','Pre-colonial and colonial history of Ghana','medium',2,'JHS1',35,'Ghana was formerly called the Gold Coast under British rule.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(16,4,NULL,NULL,'Citizenship and Democracy','Rights, responsibilities and governance','easy',3,'JHS1',30,'Citizens have both rights and responsibilities in a democracy.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(17,7,NULL,NULL,'Introduction to Religious and Moral Education','Meaning, purpose and importance of RME in daily life','easy',1,'JHS1',30,'Religious and Moral Education helps learners understand religious beliefs, moral values and responsible behaviour. It teaches respect, honesty, tolerance and peaceful living in the family, school and community.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(18,7,NULL,NULL,'God, Creation and Human Responsibility','Beliefs about creation and care for the environment','easy',2,'JHS1',35,'Many religions teach that God is the creator of the world. Human beings have a responsibility to care for creation by keeping the environment clean, protecting living things and using natural resources wisely.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(19,7,NULL,NULL,'Religious Leaders and Sacred Texts','Roles of religious leaders and the importance of holy writings','medium',3,'JHS1',35,'Religious leaders guide believers, teach moral lessons and help communities worship. Sacred texts such as the Bible, Qur\'an and traditional teachings provide guidance for faith, worship and good conduct.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(20,7,NULL,NULL,'Moral Values in the Community','Honesty, respect, obedience, kindness and responsibility','easy',4,'JHS1',30,'Moral values are principles that help people choose right actions. Values such as honesty, respect, obedience, kindness and responsibility help build trust and harmony at home, in school and in the community.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(21,7,NULL,NULL,'Peaceful Living and Conflict Resolution','How to live peacefully with others and resolve disagreements','medium',5,'JHS1',40,'Peaceful living means treating others with respect and solving problems without violence. Conflict can be resolved through listening, apologising, forgiveness, mediation and choosing fair solutions.','approved',1,NULL,NULL,NULL,'2026-05-10 17:03:13'),(22,1,NULL,NULL,'Geometry and Shapes','Study Geometry and Shapes in Mathematics at JHS1 level through clear explanations, guided examples, practical activities, and independent practice.','hard',6,'JHS1',45,'Study Geometry and Shapes in M